{"command": "cd /app/data/auto-opt/utils/llvm-105632 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/Utils/SimplifyCFG.cpp 4776 4835
// Replaces
//   (switch (ucmp/scmp X, Y)) on constant -1, 0, 1
// with a branch on the corresponding icmp predicate.
bool SimplifyCFGOpt::simplifySwitchOnCmpIntrinsic(SwitchInst *SI,
                                                   IRBuilder<> &Builder) {
  auto *CmpIntr = dyn_cast<CmpIntrinsic>(SI->getCondition());
  if (!CmpIntr)
    return false;

  // Only optimize if the CmpIntrinsic result is only used by the switch.
  if (!CmpIntr->hasOneUse())
    return false;

  // Build a map from the three possible values {-1, 0, 1} to their
  // destinations. Initialize all to the default destination.
  BasicBlock *DefaultBB = SI->getDefaultDest();
  BasicBlock *ValToBB[3] = {DefaultBB, DefaultBB, DefaultBB};
  unsigned NumExplicitCases = 0;

  for (auto &Case : SI->cases()) {
    const APInt &CaseVal = Case.getCaseValue()->getValue();
    // Only handle values -1, 0, 1
    int64_t SExtVal = CaseVal.getSExtValue();
    if (SExtVal < -1 || SExtVal > 1)
      return false;
    int64_t Idx = SExtVal + 1; // -1→0, 0→1, 1→2
    ValToBB[Idx] = Case.getCaseSuccessor();
    NumExplicitCases++;
  }

  BasicBlock *DestMinus1 = ValToBB[0];
  BasicBlock *Dest0 = ValToBB[1];
  BasicBlock *Dest1 = ValToBB[2];

  BasicBlock *CommonBB = nullptr;
  BasicBlock *OtherBB = nullptr;
  CmpInst::Predicate Pred;

  if (DestMinus1 == Dest0 && DestMinus1 != Dest1) {
    // -1 and 0 share dest, 1 is different → LHS > RHS
    CommonBB = DestMinus1;
    OtherBB = Dest1;
    Pred = CmpIntr->getGTPredicate();
  } else if (Dest0 == Dest1 && Dest0 != DestMinus1) {
    // 0 and 1 share dest, -1 is different → LHS < RHS
    CommonBB = Dest0;
    OtherBB = DestMinus1;
    Pred = CmpIntr->getLTPredicate();
  } else if (DestMinus1 == Dest1 && DestMinus1 != Dest0) {
    // -1 and 1 share dest, 0 is different → LHS == RHS
    CommonBB = DestMinus1;
    OtherBB = Dest0;
    Pred = ICmpInst::ICMP_EQ;
  } else {
    return false;
  }

  // If all three values have explicit cases, the default must be unreachable,
  // otherwise we would be removing a non-unreachable destination.
  if (NumExplicitCases == 3 &&
      !isa<UnreachableInst>(DefaultBB->getFirstNonPHIOrDbg()))
    return false;

  Value *LHS = CmpIntr->getLHS();
  Value *RHS = CmpIntr->getRHS();
  Value *Cond = Builder.CreateICmp(Pred, LHS, RHS);

  // Compute weights for the new branch.
  uint32_t TrueWeight = 0, FalseWeight = 0;
  if (hasBranchWeightMD(*SI)) {
    SmallVector<uint64_t, 8> Weights;
    getBranchWeights(SI, Weights);
    // Weights[0] is the default weight, Weights[1..N] are case weights.
    if (Weights.size() == 1 + SI->getNumCases()) {
      // Find which case indices correspond to CommonBB and which to OtherBB.
      for (auto &Case : SI->cases()) {
        unsigned Idx = Case.getSuccessorIndex();
        if (Case.getCaseSuccessor() == CommonBB)
          FalseWeight += (uint32_t)Weights[Idx];
        else if (Case.getCaseSuccessor() == OtherBB)
          TrueWeight += (uint32_t)Weights[Idx];
      }
      // If the default corresponds to one of the destinations, add its weight.
      if (DefaultBB == CommonBB)
        FalseWeight += (uint32_t)Weights[0];
      else if (DefaultBB == OtherBB)
        TrueWeight += (uint32_t)Weights[0];
    }
  }

  // The condition is true when the "OtherBB" should be taken.
  return simplifyTerminatorOnSelect(SI, Cond, OtherBB, CommonBB, TrueWeight,
                                    FalseWeight);
}
CODEEOF"}

